  <script>
    (() => {
      "use strict";

      const desktop = document.getElementById("desktop");
      const filesWindow = document.getElementById("files-window");
      const notepadWindow = document.getElementById("notepad-window");
      const openFiles = document.getElementById("open-files");
      const openNotepad = document.getElementById("open-notepad");
      let topZ = 20;

      function focusWindow(win) {
        topZ += 1;
        win.style.zIndex = topZ;
      }

      function showWindow(win, launcher) {
        win.classList.remove("hidden");
        launcher.classList.add("running");
        focusWindow(win);
      }

      openFiles.addEventListener("click", () => showWindow(filesWindow, openFiles));
      openNotepad.addEventListener("click", () => {
        showWindow(notepadWindow, openNotepad);
        requestAnimationFrame(() => document.getElementById("editor").focus());
      });

      document.querySelectorAll(".win-close").forEach(button => {
        button.addEventListener("click", event => {
          const win = event.currentTarget.closest(".app-window");
          win.classList.add("hidden");
          if (win === filesWindow) openFiles.classList.remove("running");
          if (win === notepadWindow) openNotepad.classList.remove("running");
        });
      });

      document.querySelectorAll(".app-window").forEach(win => {
        win.addEventListener("pointerdown", () => focusWindow(win));

        const bar = win.querySelector(".titlebar");
        bar.addEventListener("pointerdown", event => {
          if (event.target.closest("button") || event.button !== 0) return;

          focusWindow(win);
          const rect = win.getBoundingClientRect();
          const offsetX = event.clientX - rect.left;
          const offsetY = event.clientY - rect.top;
          bar.setPointerCapture(event.pointerId);

          const move = moveEvent => {
            const maxLeft = Math.max(0, window.innerWidth - 80);
            const maxTop = Math.max(30, window.innerHeight - 80);
            const left = Math.min(maxLeft, Math.max(0, moveEvent.clientX - offsetX));
            const top = Math.min(maxTop, Math.max(30, moveEvent.clientY - offsetY));
            win.style.left = left + "px";
            win.style.top = top + "px";
          };

          const stop = () => {
            bar.removeEventListener("pointermove", move);
            bar.removeEventListener("pointerup", stop);
            bar.removeEventListener("pointercancel", stop);
          };

          bar.addEventListener("pointermove", move);
          bar.addEventListener("pointerup", stop);
          bar.addEventListener("pointercancel", stop);
        });
      });

      function updateClock() {
        const now = new Date();
        document.getElementById("clock").textContent = now.toLocaleString([], {
          weekday: "short",
          month: "short",
          day: "numeric",
          hour: "2-digit",
          minute: "2-digit"
        });
      }

      updateClock();
      setInterval(updateClock, 15000);

      const folder = children => ({ type: "folder", children });
      const file = () => ({ type: "file" });

      const filesystem = folder({
        bin: folder({
          bash: file(),
          cat: file(),
          cp: file(),
          ls: file(),
          mkdir: file()
        }),
        etc: folder({
          network: folder({}),
          apt: folder({}),
          hostname: file(),
          hosts: file()
        }),
        home: folder({
          user: folder({
            Documents: folder({
              "Ideas.txt": file(),
              "Project Notes.txt": file(),
              "Welcome.txt": file()
            }),
            Downloads: folder({
              "ubuntu-guide.pdf": file(),
              "wallpaper.png": file()
            }),
            Pictures: folder({
              Wallpapers: folder({
                "Sunset.jpg": file(),
                "Mountains.jpg": file()
              }),
              "Desktop.png": file()
            }),
            Music: folder({}),
            Videos: folder({}),
            "todo.txt": file()
          })
        }),
        usr: folder({
          bin: folder({}),
          lib: folder({}),
          share: folder({})
        }),
        var: folder({
          log: folder({
            "system.log": file()
          }),
          cache: folder({}),
          tmp: folder({})
        }),
        opt: folder({}),
        tmp: folder({}),
        "README.txt": file()
      });

      let currentParts = [];
      const filesPath = document.getElementById("files-path");
      const filesList = document.getElementById("files-list");
      const filesUp = document.getElementById("files-up");

      function nodeAt(parts) {
        let node = filesystem;
        for (const part of parts) {
          if (!node || node.type !== "folder") return null;
          node = node.children[part];
        }
        return node;
      }

      function pathToParts(path) {
        return path.split("/").filter(Boolean);
      }

      function folderIcon() {
        return `
          <svg viewBox="0 0 56 48" aria-hidden="true">
            <path d="M3 10h21l6 7h23v26a4 4 0 0 1-4 4H7a4 4 0 0 1-4-4z" fill="#d78b1e"/>
            <path d="M3 15h50v9H3z" fill="#f1b447"/>
            <path d="M4 22h48l-4 23H8z" fill="#e4a12e"/>
          </svg>`;
      }

      function fileIcon() {
        return `
          <svg viewBox="0 0 48 52" aria-hidden="true">
            <path d="M8 2h21l11 11v35a3 3 0 0 1-3 3H8a3 3 0 0 1-3-3V5a3 3 0 0 1 3-3z" fill="#e9e6ea"/>
            <path d="M29 2v12h11" fill="#b9b5bb"/>
            <path d="M12 23h21M12 29h21M12 35h17M12 41h13" stroke="#77717a" stroke-width="2" stroke-linecap="round"/>
          </svg>`;
      }

      function navigate(pathOrParts) {
        const parts = Array.isArray(pathOrParts) ? pathOrParts : pathToParts(pathOrParts);
        const node = nodeAt(parts);
        if (!node || node.type !== "folder") return;

        currentParts = parts;
        filesPath.textContent = "/" + currentParts.join("/");
        filesUp.disabled = currentParts.length === 0;
        filesList.replaceChildren();

        const entries = Object.entries(node.children).sort((a, b) => {
          if (a[1].type !== b[1].type) return a[1].type === "folder" ? -1 : 1;
          return a[0].localeCompare(b[0]);
        });

        entries.forEach(([name, entry]) => {
          const item = document.createElement("button");
          item.type = "button";
          item.className = "fs-item";
          item.dataset.name = name;
          item.dataset.type = entry.type;
          item.innerHTML = (entry.type === "folder" ? folderIcon() : fileIcon()) +
            `<span class="fs-name"></span>`;
          item.querySelector(".fs-name").textContent = name;

          item.addEventListener("click", () => {
            filesList.querySelectorAll(".fs-item").forEach(other => other.classList.remove("selected"));
            item.classList.add("selected");
          });

          item.addEventListener("dblclick", () => {
            if (entry.type === "folder") navigate(currentParts.concat(name));
          });

          filesList.appendChild(item);
        });

        document.querySelectorAll(".place-button").forEach(button => {
          const normalized = "/" + currentParts.join("/");
          button.classList.toggle("active", button.dataset.path === normalized);
        });
      }

      filesUp.addEventListener("click", () => {
        if (currentParts.length) navigate(currentParts.slice(0, -1));
      });

      document.querySelectorAll(".place-button").forEach(button => {
        button.addEventListener("click", () => navigate(button.dataset.path));
