      navigate("/");

      const STORAGE_KEY = "ubuntuDesktopNotepadTabs";
      const tabsElement = document.getElementById("tabs");
      const newTabButton = document.getElementById("new-tab");
      const editor = document.getElementById("editor");
      const editorCount = document.getElementById("editor-count");

      let notesState = {
        tabs: [],
        activeId: null,
        nextNumber: 1
      };

      function loadNotes() {
        try {
          const saved = JSON.parse(localStorage.getItem(STORAGE_KEY));
          if (saved && Array.isArray(saved.tabs) && saved.tabs.length) {
            notesState.tabs = saved.tabs.map((tab, index) => ({
              id: String(tab.id ?? ("restored-" + index)),
              title: String(tab.title ?? ("Untitled " + (index + 1))),
              content: String(tab.content ?? "")
            }));
            notesState.activeId = notesState.tabs.some(tab => tab.id === saved.activeId)
              ? saved.activeId
              : notesState.tabs[0].id;
            notesState.nextNumber = Number.isFinite(saved.nextNumber)
              ? saved.nextNumber
              : notesState.tabs.length + 1;
            return;
          }
        } catch (_) {}

        notesState = {
          tabs: [{
            id: "tab-" + Date.now(),
            title: "Untitled 1",
            content: ""
          }],
          activeId: null,
          nextNumber: 2
        };
        notesState.activeId = notesState.tabs[0].id;
      }

      function saveNotes() {
        try {
          localStorage.setItem(STORAGE_KEY, JSON.stringify(notesState));
        } catch (_) {}
      }

      function activeTab() {
        return notesState.tabs.find(tab => tab.id === notesState.activeId);
      }

      function updateCount() {
        const count = editor.value.length;
        editorCount.textContent = count + (count === 1 ? " character" : " characters");
      }

      function renderTabs() {
        tabsElement.replaceChildren();

        notesState.tabs.forEach(tabData => {
          const tab = document.createElement("button");
          tab.type = "button";
          tab.className = "tab" + (tabData.id === notesState.activeId ? " active" : "");
          tab.textContent = tabData.title;
          tab.dataset.id = tabData.id;
          tab.setAttribute("role", "tab");
          tab.setAttribute("aria-selected", tabData.id === notesState.activeId ? "true" : "false");

          tab.addEventListener("click", () => {
            const current = activeTab();
            if (current) current.content = editor.value;
            notesState.activeId = tabData.id;
            renderTabs();
            saveNotes();
            editor.focus();
          });

          tabsElement.appendChild(tab);
        });

        const current = activeTab();
        editor.value = current ? current.content : "";
        updateCount();

        const selected = tabsElement.querySelector(".tab.active");
        if (selected) selected.scrollIntoView({ block: "nearest", inline: "nearest" });
      }

      newTabButton.addEventListener("click", () => {
        const current = activeTab();
        if (current) current.content = editor.value;

        const number = notesState.nextNumber++;
        const newTab = {
          id: "tab-" + Date.now() + "-" + Math.random().toString(36).slice(2),
          title: "Untitled " + number,
          content: ""
        };

        notesState.tabs.push(newTab);
        notesState.activeId = newTab.id;
        renderTabs();
        saveNotes();
        editor.focus();
      });

      editor.addEventListener("input", () => {
        const current = activeTab();
        if (current) {
          current.content = editor.value;
          saveNotes();
        }
        updateCount();
      });

      loadNotes();
      renderTabs();
      saveNotes();
    })();
  </script>
